class Solution:
    def countCompleteSubarrays(self, nums):
        total = len(set(nums))
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i, n):
                if len(set(nums[i:j + 1])) == total:
                    count += 1
        return count

