class Solution:
    def countCompleteSubarrays(self, nums):
        total = len(set(nums))
        n = len(nums)
        freq = {}
        left = 0
        ans = 0
        for right in range(n):
            freq[nums[right]] = freq.get(nums[right], 0) + 1
            while len(freq) == total:
                ans += n - right
                lv = nums[left]
                freq[lv] -= 1
                if freq[lv] == 0:
                    del freq[lv]
                left += 1
        return ans

